onClick:
{{
(() => {

  if (!InputName.text.trim()) {
    showAlert("Podaj nazwisko oraz imię.", "warning");
    return;
  }

  if (!InputMail.text.trim()) {
    showAlert("Podaj adres e-mail.", "warning");
    return;
  }

  if (!InputPassword.text.trim()) {
    showAlert("Podaj hasło.", "warning");
    return;
  }

  if (!SelectRole.selectedOptionValue) {
    showAlert("Wybierz rolę.", "warning");
    return;
  }

  insertUser.run(
    () => {

      getUsers.run(
        () => {

          closeModal("ModalDodajUzytkownika");

          resetWidget("InputName", true);
          resetWidget("InputMail", true);
          resetWidget("InputPassword", true);
          resetWidget("SelectRole", true);

          showAlert("Użytkownik został dodany.", "success");

        },
        (error) => {
          showAlert(
            "Nie udało się odświeżyć listy użytkowników.",
            "warning"
          );
          console.error(error);
        }
      );

    },
    (error) => {

      const errorText = String(error);

      if (errorText.includes("users_mail_key")) {
        showAlert(
          "Użytkownik z podanym adresem e-mail już istnieje.",
          "warning"
        );
        return;
      }

      showAlert(
        "Błąd podczas dodawania użytkownika.",
        "error"
      );

      console.error(error);

    }
  );

})();
}}
